    28→// determineEffectiveSecurityContext gets container's security context from v1.Pod and v1.Container.
    29→func (m *kubeGenericRuntimeManager) determineEffectiveSecurityContext(pod *v1.Pod, container *v1.Container, uid *int64, username string) (*runtimeapi.LinuxContainerSecurityContext, error) {
    30→	effectiveSc := securitycontext.DetermineEffectiveSecurityContext(pod, container)
    31→	synthesized := convertToRuntimeSecurityContext(effectiveSc)
    32→	if synthesized == nil {
    33→		synthesized = &runtimeapi.LinuxContainerSecurityContext{
    34→			MaskedPaths:   securitycontext.ConvertToRuntimeMaskedPaths(effectiveSc.ProcMount),
    35→			ReadonlyPaths: securitycontext.ConvertToRuntimeReadonlyPaths(effectiveSc.ProcMount),
    36→		}
    37→	}
    38→	var err error
    39→
    40→	synthesized.Seccomp, err = m.getSeccompProfile(pod.Annotations, container.Name, pod.Spec.SecurityContext, container.SecurityContext, m.seccompDefault)
    41→	if err != nil {
    42→		return nil, err
    43→	}
    44→
    45→	// set ApparmorProfile.
    46→	synthesized.Apparmor, synthesized.ApparmorProfile, err = getAppArmorProfile(pod, container)
    47→	if err != nil {
    48→		return nil, err
    49→	}
    50→
    51→	// set RunAsUser.
    52→	if synthesized.RunAsUser == nil {
    53→		if uid != nil {
    54→			synthesized.RunAsUser = &runtimeapi.Int64Value{Value: *uid}
    55→		}
    56→		synthesized.RunAsUsername = username
    57→	}
    58→
    59→	// set namespace options and supplemental groups.
    60→	namespaceOptions, err := runtimeutil.NamespacesForPod(pod, m.runtimeHelper, m.runtimeClassManager)
    61→	if err != nil {
    62→		return nil, err
    63→	}
    64→	synthesized.NamespaceOptions = namespaceOptions
    65→	podSc := pod.Spec.SecurityContext
    66→	if podSc != nil {
    67→		if podSc.FSGroup != nil {
    68→			synthesized.SupplementalGroups = append(synthesized.SupplementalGroups, int64(*podSc.FSGroup))
    69→		}
    70→
    71→		if podSc.SupplementalGroups != nil {
    72→			for _, sg := range podSc.SupplementalGroups {
    73→				synthesized.SupplementalGroups = append(synthesized.SupplementalGroups, int64(sg))
    74→			}
    75→		}
    76→
    77→		if podSc.SupplementalGroupsPolicy != nil {
    78→			policyValue, ok := runtimeapi.SupplementalGroupsPolicy_value[string(*podSc.SupplementalGroupsPolicy)]
    79→			if !ok {
    80→				return nil, fmt.Errorf("unsupported supplementalGroupsPolicy: %s", string(*podSc.SupplementalGroupsPolicy))
    81→			}
    82→			synthesized.SupplementalGroupsPolicy = runtimeapi.SupplementalGroupsPolicy(policyValue)
    83→		}
    84→	}
    85→	if groups := m.runtimeHelper.GetExtraSupplementalGroupsForPod(pod); len(groups) > 0 {
    86→		synthesized.SupplementalGroups = append(synthesized.SupplementalGroups, groups...)
    87→	}
    88→
    89→	synthesized.NoNewPrivs = securitycontext.AddNoNewPrivileges(effectiveSc)
    90→
    91→	synthesized.MaskedPaths = securitycontext.ConvertToRuntimeMaskedPaths(effectiveSc.ProcMount)
    92→	synthesized.ReadonlyPaths = securitycontext.ConvertToRuntimeReadonlyPaths(effectiveSc.ProcMount)
    93→
    94→	return synthesized, nil
    95→}
