    97→// convertToRuntimeSecurityContext converts v1.SecurityContext to runtimeapi.SecurityContext.
    98→func convertToRuntimeSecurityContext(securityContext *v1.SecurityContext) *runtimeapi.LinuxContainerSecurityContext {
    99→	if securityContext == nil {
   100→		return nil
   101→	}
   102→
   103→	sc := &runtimeapi.LinuxContainerSecurityContext{
   104→		Capabilities:   convertToRuntimeCapabilities(securityContext.Capabilities),
   105→		SelinuxOptions: convertToRuntimeSELinuxOption(securityContext.SELinuxOptions),
   106→	}
   107→	if securityContext.RunAsUser != nil {
   108→		sc.RunAsUser = &runtimeapi.Int64Value{Value: int64(*securityContext.RunAsUser)}
   109→	}
   110→	if securityContext.RunAsGroup != nil {
   111→		sc.RunAsGroup = &runtimeapi.Int64Value{Value: int64(*securityContext.RunAsGroup)}
   112→	}
   113→	if securityContext.Privileged != nil {
   114→		sc.Privileged = *securityContext.Privileged
   115→	}
   116→	if securityContext.ReadOnlyRootFilesystem != nil {
   117→		sc.ReadonlyRootfs = *securityContext.ReadOnlyRootFilesystem
   118→	}
   119→
   120→	return sc
   121→}
