   137→// convertToRuntimeCapabilities converts v1.Capabilities to runtimeapi.Capability.
   138→func convertToRuntimeCapabilities(opts *v1.Capabilities) *runtimeapi.Capability {
   139→	if opts == nil {
   140→		return nil
   141→	}
